import { motion, AnimatePresence } from 'framer-motion';
import { useEffect, useState, useRef, useCallback } from 'react';

// ============================================================================
// DATA FLOW ANIMATION SYSTEM
// Creates jaw-dropping visual flow: Chat → Orb → Notes Panel
// ============================================================================

interface Particle {
  id: string;
  x: number;
  y: number;
  targetX: number;
  targetY: number;
  color: string;
  size: number;
  delay: number;
  duration: number;
}

interface FlyingTextProps {
  text: string;
  fromRect: DOMRect;
  toRect: DOMRect;
  onComplete?: () => void;
  direction: 'to-orb' | 'from-orb';
}

// Flying text that travels between elements - DRAMATIC VERSION
function FlyingText({ text, fromRect, toRect, onComplete, direction }: FlyingTextProps) {
  const isToOrb = direction === 'to-orb';
  
  // Calculate center points
  const startX = fromRect.left + fromRect.width / 2;
  const startY = fromRect.top + fromRect.height / 2;
  const endX = toRect.left + toRect.width / 2;
  const endY = toRect.top + toRect.height / 2;
  
  // Create a curved path - more dramatic arc
  const midX = (startX + endX) / 2 + (isToOrb ? -80 : 80);
  const midY = Math.min(startY, endY) - 150; // Higher arc
  
  // Split text into words for particle effect
  const words = text.split(' ').slice(0, 6);
  
  return (
    <>
      {/* Main flying text container */}
      <motion.div
        className="fixed pointer-events-none z-[9999]"
        initial={{ 
          x: startX - 120, 
          y: startY - 25,
          scale: isToOrb ? 1.2 : 0.3,
          opacity: 0,
          rotate: isToOrb ? 0 : 15,
        }}
        animate={{ 
          x: [startX - 120, midX - 80, endX - 60],
          y: [startY - 25, midY, endY - 20],
          scale: isToOrb ? [1.2, 1, 0.4] : [0.4, 1, 1.1],
          opacity: [0, 1, 1, isToOrb ? 0 : 1],
          rotate: isToOrb ? [0, -5, 0] : [15, 5, 0],
        }}
        transition={{
          duration: 1.0,
          ease: [0.22, 1, 0.36, 1],
          times: [0, 0.3, 1],
        }}
        onAnimationComplete={onComplete}
      >
        <div 
          className={`px-5 py-3 rounded-2xl backdrop-blur-md max-w-[280px] ${
            isToOrb 
              ? 'bg-gradient-to-r from-cyan-500 to-blue-500 text-white font-medium' 
              : 'bg-gradient-to-r from-purple-500/90 to-cyan-500/90 border-2 border-cyan-300/50 text-white font-medium'
          }`}
          style={{
            boxShadow: isToOrb 
              ? '0 0 40px rgba(6, 182, 212, 0.7), 0 0 80px rgba(6, 182, 212, 0.4), 0 4px 20px rgba(0,0,0,0.3)'
              : '0 0 40px rgba(139, 92, 246, 0.6), 0 0 80px rgba(6, 182, 212, 0.3), 0 4px 20px rgba(0,0,0,0.3)',
          }}
        >
          <p className="text-sm leading-relaxed">{text.slice(0, 60)}{text.length > 60 ? '...' : ''}</p>
        </div>
        
        {/* Trailing glow effect */}
        <motion.div
          className="absolute inset-0 -z-10 rounded-2xl blur-xl"
          style={{
            background: isToOrb 
              ? 'linear-gradient(135deg, rgba(6, 182, 212, 0.5), rgba(59, 130, 246, 0.3))'
              : 'linear-gradient(135deg, rgba(139, 92, 246, 0.5), rgba(6, 182, 212, 0.3))',
          }}
          animate={{ 
            scale: [1, 1.5, 1],
            opacity: [0.8, 0.4, 0.8],
          }}
          transition={{ duration: 0.4, repeat: 2 }}
        />
      </motion.div>
      
      {/* Additional flying word particles for "shatter" effect when going to orb */}
      {isToOrb && words.map((word, i) => (
        <motion.div
          key={`word-${i}`}
          className="fixed pointer-events-none z-[9998] text-xs text-cyan-300 font-medium"
          initial={{ 
            x: startX - 100 + (i * 20), 
            y: startY - 10 + (i % 2 === 0 ? -10 : 10),
            opacity: 0,
            scale: 0.8,
          }}
          animate={{ 
            x: endX - 20 + (Math.random() - 0.5) * 60,
            y: endY - 20 + (Math.random() - 0.5) * 40,
            opacity: [0, 0.8, 0],
            scale: [0.8, 1, 0.3],
          }}
          transition={{
            duration: 0.7,
            delay: i * 0.08,
            ease: 'easeOut',
          }}
          style={{
            textShadow: '0 0 10px rgba(6, 182, 212, 0.8)',
          }}
        >
          {word}
        </motion.div>
      ))}
    </>
  );
}

// Particle burst effect - DRAMATIC VERSION
function ParticleBurst({ x, y, count = 20, color = '#06B6D4' }: { 
  x: number; 
  y: number; 
  count?: number; 
  color?: string;
}) {
  const particles = Array.from({ length: count }, (_, i) => {
    const angle = (i / count) * Math.PI * 2;
    const velocity = 80 + Math.random() * 150;
    return {
      id: `particle-${i}`,
      angle,
      velocity,
      size: 4 + Math.random() * 8,
      delay: Math.random() * 0.1,
    };
  });

  return (
    <div className="fixed pointer-events-none z-[9998]" style={{ left: x, top: y }}>
      {/* Central flash */}
      <motion.div
        className="absolute rounded-full"
        style={{
          width: 60,
          height: 60,
          left: -30,
          top: -30,
          background: `radial-gradient(circle, ${color} 0%, transparent 70%)`,
        }}
        initial={{ scale: 0.5, opacity: 1 }}
        animate={{ scale: 3, opacity: 0 }}
        transition={{ duration: 0.5 }}
      />
      
      {/* Particles */}
      {particles.map(p => (
        <motion.div
          key={p.id}
          className="absolute rounded-full"
          style={{
            width: p.size,
            height: p.size,
            left: -p.size / 2,
            top: -p.size / 2,
            backgroundColor: color,
            boxShadow: `0 0 ${p.size * 3}px ${color}, 0 0 ${p.size * 6}px ${color}`,
          }}
          initial={{ x: 0, y: 0, opacity: 1, scale: 1.5 }}
          animate={{
            x: Math.cos(p.angle) * p.velocity,
            y: Math.sin(p.angle) * p.velocity,
            opacity: [1, 0.8, 0],
            scale: [1.5, 1, 0],
          }}
          transition={{ 
            duration: 0.8, 
            ease: 'easeOut',
            delay: p.delay,
          }}
        />
      ))}
    </div>
  );
}

// Stream of particles flowing between points
function ParticleStream({ 
  fromRect, 
  toRect, 
  active, 
  direction = 'to-orb',
  intensity = 1,
}: { 
  fromRect: DOMRect | null; 
  toRect: DOMRect | null; 
  active: boolean;
  direction?: 'to-orb' | 'from-orb';
  intensity?: number;
}) {
  const [particles, setParticles] = useState<Particle[]>([]);
  const intervalRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    if (!active || !fromRect || !toRect) {
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
        intervalRef.current = null;
      }
      return;
    }

    const createParticle = (): Particle => {
      const isToOrb = direction === 'to-orb';
      const startRect = isToOrb ? fromRect : toRect;
      const endRect = isToOrb ? toRect : fromRect;
      
      const colors = ['#06B6D4', '#0EA5E9', '#8B5CF6', '#22D3EE', '#3B82F6'];
      
      return {
        id: `p-${Date.now()}-${Math.random()}`,
        x: startRect.left + Math.random() * startRect.width,
        y: startRect.top + Math.random() * startRect.height,
        targetX: endRect.left + endRect.width / 2 + (Math.random() - 0.5) * 40,
        targetY: endRect.top + endRect.height / 2 + (Math.random() - 0.5) * 40,
        color: colors[Math.floor(Math.random() * colors.length)],
        size: 3 + Math.random() * 5,
        delay: Math.random() * 0.2,
        duration: 0.4 + Math.random() * 0.3,
      };
    };

    // Generate initial burst
    const initialBurst = Array.from({ length: Math.floor(8 * intensity) }, createParticle);
    setParticles(initialBurst);

    // Continue generating particles
    intervalRef.current = setInterval(() => {
      setParticles(prev => {
        // Keep only recent particles, add new ones
        const recent = prev.filter(p => 
          Date.now() - parseInt(p.id.split('-')[1]) < 800
        );
        const newParticles = Array.from({ length: Math.floor(3 * intensity) }, createParticle);
        return [...recent, ...newParticles];
      });
    }, 100);

    return () => {
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
      }
    };
  }, [active, fromRect, toRect, direction, intensity]);

  if (!active || !fromRect || !toRect) return null;

  return (
    <div className="fixed inset-0 pointer-events-none z-[9997]">
      <AnimatePresence>
        {particles.map(p => (
          <motion.div
            key={p.id}
            className="absolute rounded-full"
            style={{
              width: p.size,
              height: p.size,
              backgroundColor: p.color,
              boxShadow: `0 0 ${p.size * 3}px ${p.color}`,
            }}
            initial={{ 
              x: p.x, 
              y: p.y, 
              opacity: 0,
              scale: direction === 'to-orb' ? 1 : 0.5,
            }}
            animate={{ 
              x: p.targetX, 
              y: p.targetY, 
              opacity: [0, 1, 1, 0],
              scale: direction === 'to-orb' ? [1, 0.8, 0.5] : [0.5, 0.8, 1],
            }}
            exit={{ opacity: 0 }}
            transition={{
              duration: p.duration,
              delay: p.delay,
              ease: [0.22, 1, 0.36, 1],
            }}
          />
        ))}
      </AnimatePresence>
    </div>
  );
}

// Energy ring pulse effect - DRAMATIC VERSION with multiple rings
function EnergyRing({ x, y, size, color = '#06B6D4' }: { 
  x: number; 
  y: number; 
  size: number;
  color?: string;
}) {
  return (
    <>
      {/* Primary ring */}
      <motion.div
        className="fixed pointer-events-none z-[9996] rounded-full border-4"
        style={{
          left: x - size / 2,
          top: y - size / 2,
          width: size,
          height: size,
          borderColor: color,
          boxShadow: `0 0 30px ${color}, 0 0 60px ${color}, inset 0 0 30px ${color}`,
        }}
        initial={{ scale: 0.3, opacity: 1 }}
        animate={{ scale: 2.5, opacity: 0 }}
        transition={{ duration: 0.8, ease: 'easeOut' }}
      />
      
      {/* Secondary ring - delayed */}
      <motion.div
        className="fixed pointer-events-none z-[9996] rounded-full border-2"
        style={{
          left: x - size / 2,
          top: y - size / 2,
          width: size,
          height: size,
          borderColor: color,
          boxShadow: `0 0 20px ${color}`,
        }}
        initial={{ scale: 0.5, opacity: 0.8 }}
        animate={{ scale: 3, opacity: 0 }}
        transition={{ duration: 1, ease: 'easeOut', delay: 0.15 }}
      />
      
      {/* Tertiary ring - more delayed */}
      <motion.div
        className="fixed pointer-events-none z-[9996] rounded-full border"
        style={{
          left: x - size / 2,
          top: y - size / 2,
          width: size,
          height: size,
          borderColor: color,
          opacity: 0.5,
        }}
        initial={{ scale: 0.7, opacity: 0.5 }}
        animate={{ scale: 3.5, opacity: 0 }}
        transition={{ duration: 1.2, ease: 'easeOut', delay: 0.3 }}
      />
      
      {/* Center flash */}
      <motion.div
        className="fixed pointer-events-none z-[9997] rounded-full"
        style={{
          left: x - 40,
          top: y - 40,
          width: 80,
          height: 80,
          background: `radial-gradient(circle, white 0%, ${color} 30%, transparent 70%)`,
        }}
        initial={{ scale: 0, opacity: 1 }}
        animate={{ scale: 2, opacity: 0 }}
        transition={{ duration: 0.4, ease: 'easeOut' }}
      />
    </>
  );
}

// ============================================================================
// MAIN DATA FLOW CONTROLLER
// Orchestrates all animations between Chat, Orb, and Notes Panel
// ============================================================================

export interface DataFlowAnimationRef {
  triggerMessageToOrb: (message: string, fromElement?: HTMLElement) => void;
  triggerInsightFromOrb: (insightText: string, toElement?: HTMLElement) => void;
  setOrbRef: (ref: HTMLElement | null) => void;
  setNotesRef: (ref: HTMLElement | null) => void;
  setChatRef: (ref: HTMLElement | null) => void;
}

interface DataFlowState {
  flyingTexts: Array<{
    id: string;
    text: string;
    fromRect: DOMRect;
    toRect: DOMRect;
    direction: 'to-orb' | 'from-orb';
  }>;
  particleBursts: Array<{
    id: string;
    x: number;
    y: number;
    color: string;
  }>;
  energyRings: Array<{
    id: string;
    x: number;
    y: number;
    size: number;
    color: string;
  }>;
  particleStreamActive: boolean;
  particleStreamDirection: 'to-orb' | 'from-orb';
}

interface DataFlowAnimationProps {
  onOrbIngest?: () => void;
  onOrbRelease?: () => void;
  children: (ref: DataFlowAnimationRef) => React.ReactNode;
}

export function DataFlowAnimation({ 
  onOrbIngest, 
  onOrbRelease, 
  children 
}: DataFlowAnimationProps) {
  const [state, setState] = useState<DataFlowState>({
    flyingTexts: [],
    particleBursts: [],
    energyRings: [],
    particleStreamActive: false,
    particleStreamDirection: 'to-orb',
  });

  const orbRef = useRef<HTMLElement | null>(null);
  const notesRef = useRef<HTMLElement | null>(null);
  const chatRef = useRef<HTMLElement | null>(null);

  const getOrbCenter = useCallback(() => {
    if (!orbRef.current) return null;
    const rect = orbRef.current.getBoundingClientRect();
    return { x: rect.left + rect.width / 2, y: rect.top + rect.height / 2 };
  }, []);

  const triggerMessageToOrb = useCallback((message: string, fromElement?: HTMLElement) => {
    if (!orbRef.current) return;
    
    const fromRect = fromElement?.getBoundingClientRect() || 
      chatRef.current?.getBoundingClientRect();
    const toRect = orbRef.current.getBoundingClientRect();
    
    if (!fromRect) return;

    const id = `flying-${Date.now()}`;
    
    // Add flying text
    setState(prev => ({
      ...prev,
      flyingTexts: [...prev.flyingTexts, {
        id,
        text: message,
        fromRect,
        toRect,
        direction: 'to-orb' as const,
      }],
      particleStreamActive: true,
      particleStreamDirection: 'to-orb',
    }));

    // Trigger particle stream
    setTimeout(() => {
      const orbCenter = getOrbCenter();
      if (orbCenter) {
        // Add energy ring on arrival
        setState(prev => ({
          ...prev,
          energyRings: [...prev.energyRings, {
            id: `ring-${Date.now()}`,
            x: orbCenter.x,
            y: orbCenter.y,
            size: 100,
            color: '#06B6D4',
          }],
          particleBursts: [...prev.particleBursts, {
            id: `burst-${Date.now()}`,
            x: orbCenter.x,
            y: orbCenter.y,
            color: '#06B6D4',
          }],
        }));
        
        // Callback to grow/pulse the orb
        onOrbIngest?.();
      }
    }, 600);

    // Stop particle stream after animation
    setTimeout(() => {
      setState(prev => ({
        ...prev,
        particleStreamActive: false,
      }));
    }, 1000);

    // Clean up flying text
    setTimeout(() => {
      setState(prev => ({
        ...prev,
        flyingTexts: prev.flyingTexts.filter(f => f.id !== id),
      }));
    }, 1000);

    // Clean up effects
    setTimeout(() => {
      setState(prev => ({
        ...prev,
        particleBursts: [],
        energyRings: [],
      }));
    }, 1500);
  }, [getOrbCenter, onOrbIngest]);

  const triggerInsightFromOrb = useCallback((insightText: string, toElement?: HTMLElement) => {
    if (!orbRef.current) return;
    
    const fromRect = orbRef.current.getBoundingClientRect();
    const toRect = toElement?.getBoundingClientRect() || 
      notesRef.current?.getBoundingClientRect();
    
    if (!toRect) return;

    const id = `insight-${Date.now()}`;
    const orbCenter = getOrbCenter();

    // Start with energy release from orb
    if (orbCenter) {
      setState(prev => ({
        ...prev,
        energyRings: [...prev.energyRings, {
          id: `ring-${Date.now()}`,
          x: orbCenter.x,
          y: orbCenter.y,
          size: 80,
          color: '#8B5CF6',
        }],
        particleStreamActive: true,
        particleStreamDirection: 'from-orb',
      }));
      
      onOrbRelease?.();
    }

    // Add flying text after brief delay
    setTimeout(() => {
      setState(prev => ({
        ...prev,
        flyingTexts: [...prev.flyingTexts, {
          id,
          text: insightText,
          fromRect,
          toRect,
          direction: 'from-orb' as const,
        }],
      }));
    }, 200);

    // Stop particle stream
    setTimeout(() => {
      setState(prev => ({
        ...prev,
        particleStreamActive: false,
      }));
    }, 1000);

    // Clean up
    setTimeout(() => {
      setState(prev => ({
        ...prev,
        flyingTexts: prev.flyingTexts.filter(f => f.id !== id),
        energyRings: [],
      }));
    }, 1200);
  }, [getOrbCenter, onOrbRelease]);

  const animationRef: DataFlowAnimationRef = {
    triggerMessageToOrb,
    triggerInsightFromOrb,
    setOrbRef: (ref) => { orbRef.current = ref; },
    setNotesRef: (ref) => { notesRef.current = ref; },
    setChatRef: (ref) => { chatRef.current = ref; },
  };

  return (
    <>
      {children(animationRef)}
      
      {/* Flying texts */}
      <AnimatePresence>
        {state.flyingTexts.map(ft => (
          <FlyingText
            key={ft.id}
            text={ft.text}
            fromRect={ft.fromRect}
            toRect={ft.toRect}
            direction={ft.direction}
          />
        ))}
      </AnimatePresence>

      {/* Particle bursts */}
      <AnimatePresence>
        {state.particleBursts.map(pb => (
          <ParticleBurst
            key={pb.id}
            x={pb.x}
            y={pb.y}
            color={pb.color}
          />
        ))}
      </AnimatePresence>

      {/* Energy rings */}
      <AnimatePresence>
        {state.energyRings.map(er => (
          <EnergyRing
            key={er.id}
            x={er.x}
            y={er.y}
            size={er.size}
            color={er.color}
          />
        ))}
      </AnimatePresence>

      {/* Particle stream */}
      <ParticleStream
        fromRect={chatRef.current?.getBoundingClientRect() || null}
        toRect={orbRef.current?.getBoundingClientRect() || null}
        active={state.particleStreamActive}
        direction={state.particleStreamDirection}
      />
    </>
  );
}

// ============================================================================
// HOOK for easier integration
// ============================================================================

export function useDataFlow() {
  const animationRef = useRef<DataFlowAnimationRef | null>(null);
  
  return {
    setRef: (ref: DataFlowAnimationRef | null) => {
      animationRef.current = ref;
    },
    triggerMessageToOrb: (message: string, fromElement?: HTMLElement) => {
      animationRef.current?.triggerMessageToOrb(message, fromElement);
    },
    triggerInsightFromOrb: (insightText: string, toElement?: HTMLElement) => {
      animationRef.current?.triggerInsightFromOrb(insightText, toElement);
    },
    setOrbRef: (ref: HTMLElement | null) => {
      animationRef.current?.setOrbRef(ref);
    },
    setNotesRef: (ref: HTMLElement | null) => {
      animationRef.current?.setNotesRef(ref);
    },
    setChatRef: (ref: HTMLElement | null) => {
      animationRef.current?.setChatRef(ref);
    },
  };
}
